import{_ as a,o as i,c as o,ai as t}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"Voice Wake","description":"","frontmatter":{"summary":"Voice wake and push-to-talk modes plus routing details in the mac app","read_when":["Working on voice wake or PTT pathways"],"title":"Voice Wake"},"headers":[],"relativePath":"platforms/mac/voicewake.md","filePath":"platforms/mac/voicewake.md","lastUpdated":1771906665000}'),r={name:"platforms/mac/voicewake.md"};function s(l,e,n,d,c,h){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="voice-wake-push-to-talk" tabindex="-1"><a class="header-anchor" href="#voice-wake-push-to-talk">#</a> Voice Wake &amp; Push-to-Talk</h1><h2 id="modes" tabindex="-1"><a class="header-anchor" href="#modes">#</a> Modes</h2><ul><li><strong>Wake-word mode</strong> (default): always-on Speech recognizer waits for trigger tokens (<code>swabbleTriggerWords</code>). On match it starts capture, shows the overlay with partial text, and auto-sends after silence.</li><li><strong>Push-to-talk (Right Option hold)</strong>: hold the right Option key to capture immediately—no trigger needed. The overlay appears while held; releasing finalizes and forwards after a short delay so you can tweak text.</li></ul><h2 id="runtime-behavior-wake-word" tabindex="-1"><a class="header-anchor" href="#runtime-behavior-wake-word">#</a> Runtime behavior (wake-word)</h2><ul><li>Speech recognizer lives in <code>VoiceWakeRuntime</code>.</li><li>Trigger only fires when there’s a <strong>meaningful pause</strong> between the wake word and the next word (~0.55s gap). The overlay/chime can start on the pause even before the command begins.</li><li>Silence windows: 2.0s when speech is flowing, 5.0s if only the trigger was heard.</li><li>Hard stop: 120s to prevent runaway sessions.</li><li>Debounce between sessions: 350ms.</li><li>Overlay is driven via <code>VoiceWakeOverlayController</code> with committed/volatile coloring.</li><li>After send, recognizer restarts cleanly to listen for the next trigger.</li></ul><h2 id="lifecycle-invariants" tabindex="-1"><a class="header-anchor" href="#lifecycle-invariants">#</a> Lifecycle invariants</h2><ul><li>If Voice Wake is enabled and permissions are granted, the wake-word recognizer should be listening (except during an explicit push-to-talk capture).</li><li>Overlay visibility (including manual dismiss via the X button) must never prevent the recognizer from resuming.</li></ul><h2 id="sticky-overlay-failure-mode-previous" tabindex="-1"><a class="header-anchor" href="#sticky-overlay-failure-mode-previous">#</a> Sticky overlay failure mode (previous)</h2><p>Previously, if the overlay got stuck visible and you manually closed it, Voice Wake could appear “dead” because the runtime’s restart attempt could be blocked by overlay visibility and no subsequent restart was scheduled.</p><p>Hardening:</p><ul><li>Wake runtime restart is no longer blocked by overlay visibility.</li><li>Overlay dismiss completion triggers a <code>VoiceWakeRuntime.refresh(...)</code> via <code>VoiceSessionCoordinator</code>, so manual X-dismiss always resumes listening.</li></ul><h2 id="push-to-talk-specifics" tabindex="-1"><a class="header-anchor" href="#push-to-talk-specifics">#</a> Push-to-talk specifics</h2><ul><li>Hotkey detection uses a global <code>.flagsChanged</code> monitor for <strong>right Option</strong> (<code>keyCode 61</code> + <code>.option</code>). We only observe events (no swallowing).</li><li>Capture pipeline lives in <code>VoicePushToTalk</code>: starts Speech immediately, streams partials to the overlay, and calls <code>VoiceWakeForwarder</code> on release.</li><li>When push-to-talk starts we pause the wake-word runtime to avoid dueling audio taps; it restarts automatically after release.</li><li>Permissions: requires Microphone + Speech; seeing events needs Accessibility/Input Monitoring approval.</li><li>External keyboards: some may not expose right Option as expected—offer a fallback shortcut if users report misses.</li></ul><h2 id="user-facing-settings" tabindex="-1"><a class="header-anchor" href="#user-facing-settings">#</a> User-facing settings</h2><ul><li><strong>Voice Wake</strong> toggle: enables wake-word runtime.</li><li><strong>Hold Cmd+Fn to talk</strong>: enables the push-to-talk monitor. Disabled on macOS &lt; 26.</li><li>Language &amp; mic pickers, live level meter, trigger-word table, tester (local-only; does not forward).</li><li>Mic picker preserves the last selection if a device disconnects, shows a disconnected hint, and temporarily falls back to the system default until it returns.</li><li><strong>Sounds</strong>: chimes on trigger detect and on send; defaults to the macOS “Glass” system sound. You can pick any <code>NSSound</code>-loadable file (e.g. MP3/WAV/AIFF) for each event or choose <strong>No Sound</strong>.</li></ul><h2 id="forwarding-behavior" tabindex="-1"><a class="header-anchor" href="#forwarding-behavior">#</a> Forwarding behavior</h2><ul><li>When Voice Wake is enabled, transcripts are forwarded to the active gateway/agent (the same local vs remote mode used by the rest of the mac app).</li><li>Replies are delivered to the <strong>last-used main provider</strong> (WhatsApp/Telegram/Discord/WebChat). If delivery fails, the error is logged and the run is still visible via WebChat/session logs.</li></ul><h2 id="forwarding-payload" tabindex="-1"><a class="header-anchor" href="#forwarding-payload">#</a> Forwarding payload</h2><ul><li><code>VoiceWakeForwarder.prefixedTranscript(_:)</code> prepends the machine hint before sending. Shared between wake-word and push-to-talk paths.</li></ul><h2 id="quick-verification" tabindex="-1"><a class="header-anchor" href="#quick-verification">#</a> Quick verification</h2><ul><li>Toggle push-to-talk on, hold Cmd+Fn, speak, release: overlay should show partials then send.</li><li>While holding, menu-bar ears should stay enlarged (uses <code>triggerVoiceEars(ttl:nil)</code>); they drop after release.</li></ul>',21)])])}const g=a(r,[["render",s]]);export{p as __pageData,g as default};
